sql:
SELECT crime_id, category, observed 
FROM crime_data 
WHERE category = 'Violent crime' AND observed > 50;

SELECT category, observed, trend
FROM crime_data
ORDER BY trend DESC;

external_knowledge:
- "most active" refers to departments represented by officers who report crimes in the top regions;
- "greatest surge in criminal activity" corresponds to areas with the highest observed frequencies of crime;
- "reported incidents" refers to the observed frequency of crimes.

sql:
SELECT area_code, area_name 
FROM crime_data 
WHERE crime_id = 1;

SELECT crime_id, observed 
FROM crime_data 
WHERE crime_id < 10 AND observed > 80;

SELECT area_name, crime_rate
FROM areas
WHERE crime_rate > (SELECT AVG(crime_rate) FROM areas);

external_knowledge:
- "shadows cast by the violent hands" refers to violent crimes;
- "navigating through the streets of Trafford" indicates the location of the crimes, specifically the area named Trafford;
- "identifiers, nature, frequency, trends, and stories of their dark deeds" refers to crime_id, category, observed, trend, and incident_description.

sql:
SELECT area_name, AVG(trend) AS Average_Trend
FROM crime_data
GROUP BY area_name;

external_knowledge:
- "traffic lights of the city" - metaphorically represents the crimes reported by the Traffic department;
- "illuminating" - symbolizes the occurrences or reports of crimes;
- "Traffic department's radar" - refers to the monitoring system or the department's focus area;
- "from the beginning to the end of the year 2015" - refers to the time period '2015-01-01' to '2015-12-31'.

sql:
SELECT area_name
FROM areas
WHERE area_code = '0';

SELECT DISTINCT T1.user_id
FROM users AS T1
INNER JOIN access_logs AS T2 ON T1.user_id = T2.user_id;

external_knowledge:
- "bustling regions" refers to areas with populations greater than 50,000;
- "moderate number of residents" means a population exceeding 50,000;
- "notable rise in violent offenses" indicates a positive trend in violent crime occurrences;
- "average growth trend" is calculated as the average of the trend values for violent crimes;
- "in descending order" means listing the areas from the highest average trend to the lowest.

sql:
SELECT area_name
FROM areas
WHERE average_income > (SELECT TRUNC(AVG(average_income)) FROM areas);

SELECT crime_id
FROM crime_data
WHERE category != 'Violent Crime'
AND officer_id IN (
    SELECT user_id FROM users
);

external_knowledge:
- "shouldered a heavier burden of criminal activity" metaphorically describes areas with crime counts higher than the average;
- "casting a longer shadow over the average crime rates" metaphorically indicates the areas where crime numbers significantly surpass the overall average;
- "January 2015" refers to the specific month and year for the crime data observation; 
- Average crime rates are computed by averaging the number of crimes across all areas.

sql:
SELECT area_code, area_name, AVG(crime_rate) AS avg_crime_rate
FROM areas
GROUP BY area_code, area_name;

SELECT COUNT(*) AS total_vehicle_crimes 
FROM crime_data 
WHERE category = 'Vehicle crime';

SELECT cd.*, ar.average_crime_rate
FROM (
    SELECT * FROM crime_data LIMIT 6
) AS cd
CROSS JOIN (
    SELECT AVG(crime_rate) AS average_crime_rate FROM areas
) AS ar;
